    // your code goes here
    int t;
    cin >> t;
    while (t--) {
        long n;
        cin >> n;
        if (n == 1) {
            cout << 2;
        }
        // 2^k - 1 == 001111
        //             00111 ^ 01000 = 1111
        else if (((n / 2) ^ (n / 2 + 1)) == n) {
            cout << n / 2;
        }
        else {
            cout << -1;
        }
        cout << "\n";
    }
    return 0;
}

