code.JavaScript:
const readline = require('readline');

// Set up readline to handle input
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

// Array to store all input lines
const inputLines = [];
rl.on('line', (line) => {
    inputLines.push(line.trim());
});

rl.on('close', () => {
    const t = parseInt(inputLines[0], 10); // Read the number of test cases
    let result = [];

    for (let i = 1; i <= t; i++) {
        let n = BigInt(inputLines[i]); // Convert input to BigInt to handle large numbers

        if (n === BigInt(1)) {
            result.push("2");
        } else if (((n / BigInt(2)) ^ (n / BigInt(2) + BigInt(1))) === n) {
            result.push((n / BigInt(2)).toString());
        } else {
            result.push("-1");
        }
    }

    // Output all results at once
    console.log(result.join("\n"));
});
